import { useState, useMemo } from 'react';

const PRODUCTS = [
  { name: 'Keyboard', price: 79, stock: 12 },
  { name: 'Monitor', price: 329, stock: 4 },
  { name: 'Mouse', price: 29, stock: 40 },
  { name: 'Webcam', price: 99, stock: 0 },
];

export default function ProductTable() {
  const [sort, setSort] = useState({ key: 'name', dir: 1 });
  const rows = useMemo(() => {
    return [...PRODUCTS].sort((a, b) => {
      const x = a[sort.key], y = b[sort.key];
      const cmp = typeof x === 'number' ? x - y : String(x).localeCompare(String(y));
      return cmp * sort.dir;
    });
  }, [sort]);

  const toggle = (key) =>
    setSort((s) => (s.key === key ? { key, dir: -s.dir } : { key, dir: 1 }));

  return (
    <table style={{ borderCollapse: 'collapse', width: '100%' }}>
      <thead>
        <tr>
          {['name', 'price', 'stock'].map((k) => (
            <th key={k} onClick={() => toggle(k)} style={{ cursor: 'pointer', textAlign: 'left', padding: 8, borderBottom: '2px solid #ddd' }}>
              {k} {sort.key === k ? (sort.dir > 0 ? '↑' : '↓') : ''}
            </th>
          ))}
        </tr>
      </thead>
      <tbody>
        {rows.map((r) => (
          <tr key={r.name}>
            <td style={{ padding: 8 }}>{r.name}</td>
            <td style={{ padding: 8 }}>${r.price}</td>
            <td style={{ padding: 8 }}>{r.stock}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}
